import { createContext, useContext, type ReactNode } from 'react';
import type { Editor } from '@tiptap/core';
import type { BlockEditorContextValue, BlockEditorLabels, BlockEditorVariant } from './types';
import { DEFAULT_BLOCK_EDITOR_LABELS } from './labels';

const BlockEditorContext = createContext<BlockEditorContextValue | null>(null);

export function useBlockEditorContext() {
  const ctx = useContext(BlockEditorContext);
  if (!ctx) throw new Error('BlockEditor components must be used within <BlockEditor>');
  return ctx;
}

export interface BlockEditorProviderProps {
  editor: Editor | null;
  children: ReactNode;
  labels?: Partial<BlockEditorLabels>;
  variant?: BlockEditorVariant;
}

export function BlockEditorProvider({
  editor,
  children,
  labels,
  variant = "default",
}: BlockEditorProviderProps) {
  const mergedLabels = { ...DEFAULT_BLOCK_EDITOR_LABELS, ...labels };

  return (
    <BlockEditorContext.Provider
      value={{
        editor,
        labels: mergedLabels,
        variant,
      }}
    >
      {children}
    </BlockEditorContext.Provider>
  );
}

import type { BlockEditorLabels } from './types';

export const DEFAULT_BLOCK_EDITOR_LABELS: BlockEditorLabels = {
  paragraphLabel: 'Text',
  headingLabel: 'Heading',
  bulletListLabel: 'Bullet list',
  orderedListLabel: 'Numbered list',
  taskListLabel: 'To-do list',
  blockquoteLabel: 'Quote',
  codeBlockLabel: 'Code',
  dividerLabel: 'Divider',
};

import type { Editor } from '@tiptap/core';
import type { ReactNode } from 'react';

export type BlockEditorVariant = "default" | "minimal";

export interface BlockEditorLabels {
  paragraphLabel?: string;
  headingLabel?: string;
  bulletListLabel?: string;
  orderedListLabel?: string;
  taskListLabel?: string;
  blockquoteLabel?: string;
  codeBlockLabel?: string;
  dividerLabel?: string;
}

export interface BlockEditorProps {
  editor: Editor | null;
  children?: ReactNode;
  className?: string;
  labels?: Partial<BlockEditorLabels>;
  variant?: BlockEditorVariant;
}

export interface BlockEditorContextValue {
  editor: Editor | null;
  labels: BlockEditorLabels;
  variant: BlockEditorVariant;
}

/* Block Editor styles using shadcn CSS variables */

.block-editor {
  position: relative;
  width: 100%;
