  height: 0;
  pointer-events: none;
}

/* Tiptap drag handle (from @tiptap/extension-drag-handle-react) */
.drag-handle {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 1.25rem;
  height: 1.5rem;
  border-radius: calc(var(--radius) - 4px);
  background: transparent;
  color: var(--muted-foreground);
  cursor: grab;
  transition: background-color 0.1s, color 0.1s;
  opacity: 0;
}

.drag-handle:hover {
  background: var(--accent);
  color: var(--accent-foreground);
  opacity: 1;
}

.block-editor-content .ProseMirror:hover ~ .drag-handle,
.block-editor-content:hover .drag-handle {
  opacity: 1;
}

/* Bubble menu */
.block-editor-bubble-menu {
  display: flex;
  align-items: center;
  height: 2.25rem;
  background: var(--popover);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.12);
