}

.block-editor-bubble-overlay {
  position: fixed;
  inset: 0;
  z-index: 999;
}

.block-editor-bubble-dropdown {
  position: absolute;
  top: 100%;
  left: 0;
  z-index: 1000;
  min-width: 150px;
  background: var(--popover);
  border: 1px solid var(--border);
